// Utility: build reverse map (detail skill -> core skill)
let _reverseMap = null;
export function buildReverseMap() {
  if (_reverseMap) return _reverseMap;
  _reverseMap = {};
  for (const [core, details] of Object.entries(SKILL_MAP)) {
    for (const d of details) {
      const key = d.split("[")[0].trim().toLowerCase();
      if (!_reverseMap[key]) _reverseMap[key] = core;
    }
  }
  return _reverseMap;
}
